import os
from dataclasses import dataclass, field
from typing import List, Optional, Dict, Any
from enum import Enum
import hashlib
import json
import time


class SafetyLevel(Enum):
    SAFE = "safe"
    WARNING = "warning"
    BLOCKED = "blocked"
    CRITICAL = "critical"


@dataclass
class SafetyCheckResult:
    level: SafetyLevel
    reason: str
    confidence: float
    categories: List[str] = field(default_factory=list)
    metadata: Dict[str, Any] = field(default_factory=dict)


class ContentSafetyFilter:
    """Multi-layered content safety filter for generative AI applications."""

    BLOCKED_CATEGORIES = {
        "violence": SafetyLevel.BLOCKED,
        "hate_speech": SafetyLevel.BLOCKED,
        "sexual_content_minors": SafetyLevel.CRITICAL,
        "self_harm": SafetyLevel.BLOCKED,
        "illegal_activity": SafetyLevel.BLOCKED,
    }

    WARNING_CATEGORIES = {
        "medical_advice": SafetyLevel.WARNING,
        "legal_advice": SafetyLevel.WARNING,
        "financial_advice": SafetyLevel.WARNING,
        "personal_info": SafetyLevel.WARNING,
    }

    def __init__(self, api_key: Optional[str] = None):
        self.api_key = api_key or os.getenv("SAFETY_API_KEY")
        self.audit_log: List[Dict[str, Any]] = []

    def check_input(self, user_input: str) -> SafetyCheckResult:
        """Check user input for safety violations before processing."""
        result = self._analyze_content(user_input, direction="input")
        self._log_check(user_input, result, direction="input")
        return result

    def check_output(self, ai_output: str, original_input: str = "") -> SafetyCheckResult:
        """Check AI output for safety violations before returning to user."""
        result = self._analyze_content(ai_output, direction="output")
        self._log_check(ai_output, result, direction="output")
        return result

    def _analyze_content(self, content: str, direction: str) -> SafetyCheckResult:
        """Analyze content against safety policies."""
        detected_categories = []
        max_level = SafetyLevel.SAFE

        content_lower = content.lower()

        for category, level in self.BLOCKED_CATEGORIES.items():
            if self._check_category(content_lower, category):
                detected_categories.append(category)
                if level.value > max_level.value:
                    max_level = level

        for category, level in self.WARNING_CATEGORIES.items():
            if self._check_category(content_lower, category):
                detected_categories.append(category)
                if level.value > max_level.value:
                    max_level = level

        if not detected_categories:
            return SafetyCheckResult(
                level=SafetyLevel.SAFE,
                reason="No safety violations detected",
                confidence=0.95,
            )

        return SafetyCheckResult(
            level=max_level,
            reason=f"Detected categories: {', '.join(detected_categories)}",
            confidence=0.85,
            categories=detected_categories,
        )

    def _check_category(self, content: str, category: str) -> bool:
        """Check if content matches a safety category."""
        keyword_lists = {
            "violence": ["kill", "murder", "assault", "weapon", "bomb"],
            "hate_speech": ["slur", "discriminate", "inferior race"],
            "self_harm": ["suicide", "self harm", "cut myself"],
            "medical_advice": ["diagnose", "prescription", "dosage"],
            "legal_advice": ["legal strategy", "sue", "file a lawsuit"],
        }
        keywords = keyword_lists.get(category, [])
        return any(kw in content for kw in keywords)

    def _log_check(self, content: str, result: SafetyCheckResult, direction: str):
        """Log safety check for audit trail."""
        content_hash = hashlib.sha256(content.encode()).hexdigest()[:16]
        self.audit_log.append({
            "timestamp": time.time(),
            "direction": direction,
            "content_hash": content_hash,
            "level": result.level.value,
            "reason": result.reason,
            "categories": result.categories,
        })

    def get_audit_report(self) -> str:
        """Generate an audit report of all safety checks."""
        total = len(self.audit_log)
        blocked = sum(1 for log in self.audit_log if log["level"] == "blocked")
        warnings = sum(1 for log in self.audit_log if log["level"] == "warning")
        return (
            f"Audit Report: {total} checks performed, "
            f"{blocked} blocked, {warnings} warnings"
        )


class ContentWatermarker:
    """Embed and detect watermarks in AI-generated content."""

    WATERMARK_PREFIX = "[AI-GENERATED]"
    METADATA_KEY = "ai_provenance"

    def embed_watermark(self, content: str, model_id: str, metadata: Optional[Dict] = None) -> str:
        """Embed a metadata watermark in generated content."""
        provenance = {
            self.METADATA_KEY: {
                "model": model_id,
                "timestamp": time.time(),
                "content_hash": hashlib.sha256(content.encode()).hexdigest(),
                "version": "1.0",
            }
        }
        if metadata:
            provenance[self.METADATA_KEY].update(metadata)

        watermark_json = json.dumps(provenance, separators=(",", ":"))
        return f"{content}\n\n<!-- {watermark_json} -->"

    def detect_watermark(self, content: str) -> Optional[Dict]:
        """Detect if content contains an AI watermark."""
        if self.WATERMARK_PREFIX in content:
            return {"detected": True, "method": "prefix"}
        if "<!--" in content and "ai_provenance" in content:
            start = content.index("<!--") + 4
            end = content.index("-->")
            try:
                metadata = json.loads(content[start:end].strip())
                return {"detected": True, "method": "metadata", "metadata": metadata}
            except json.JSONDecodeError:
                pass
        return None


