    safety_filter = ContentSafetyFilter()
    watermarker = ContentWatermarker()

    user_query = "Write a Python function to calculate factorial"
    input_check = safety_filter.check_input(user_query)
    print(f"Input safety: {input_check.level.value}")

    ai_response = "Here is a Python factorial function:\ndef factorial(n):\n    return 1 if n <= 1 else n * factorial(n-1)"
    output_check = safety_filter.check_output(ai_response)
    print(f"Output safety: {output_check.level.value}")

    watermarked = watermarker.embed_watermark(ai_response, model_id="gpt-4o-2026")
    detection = watermarker.detect_watermark(watermarked)
    print(f"Watermark detected: {detection is not None}")

    print(safety_filter.get_audit_report())
